 1	import * as React from 'react';
 2	import { useTranslation } from 'react-i18next';
 3	import {
 4	  DescriptionListDescription,
 5	  DescriptionListGroup,
 6	  DescriptionListTerm,
 7	} from '@patternfly/react-core';
 8	import { ApprovalTaskKind } from '../../../types';
 9	
10	export interface TaskDescriptionProps {
11	  obj: ApprovalTaskKind;
12	}
13	
14	const TaskDescription: React.FC<TaskDescriptionProps> = ({ obj }) => {
15	  const { t } = useTranslation('plugin__pipelines-console-plugin');
16	  if (!obj?.spec?.description || obj?.spec?.description?.length === 0)
17	    return null;
18	
19	  return (
20	    <DescriptionListGroup data-test-id="approval-task-description">
21	      <DescriptionListTerm>{t('Description')}</DescriptionListTerm>
22	      <DescriptionListDescription>
23	        {obj.spec?.description}
24	      </DescriptionListDescription>
25	    </DescriptionListGroup>
26	  );
27	};
28	
29	export default TaskDescription;

